import React, { useEffect, useState } from "react";
import axios from "axios";
import AdminNav from "./AdminNav";

const Analytics = () => {
  const [data, setData] = useState(null);
  const [error, setError] = useState("");
  const apiURL = process.env.REACT_APP_API_URL || "http://localhost:8000";

  useEffect(() => {
    const run = async () => {
      try {
        const raw = localStorage.getItem("adminJwt");
        if (!raw) { setError("Missing admin token"); return; }
        const { token } = JSON.parse(raw);
        const res = await axios.get(`${apiURL}/api/admin/analytics/summary`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (res.data && res.data.success) setData(res.data.data);
        else setError(res.data.error || "Failed to load analytics");
      } catch (err) {
        setError("Network or authorization error");
      }
    };
    run();
  }, [apiURL]);

  return (
    <div className="max-w-6xl mx-auto mt-10 p-6 border rounded">
      <h2 className="text-2xl font-semibold mb-4">Analytics</h2>
      <AdminNav />
      {error && <div className="text-red-600 mb-3">{error}</div>}
      {!data ? (
        <p>Loading...</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="p-4 border rounded">
            <p className="text-gray-600">Total Users</p>
            <p className="text-2xl font-bold">{data.usersTotal}</p>
          </div>
          <div className="p-4 border rounded">
            <p className="text-gray-600">Hospitals</p>
            <p className="text-2xl font-bold">{data.hospitalsTotal}</p>
          </div>
          <div className="p-4 border rounded">
            <p className="text-gray-600">Patients</p>
            <p className="text-2xl font-bold">{data.patientsTotal}</p>
          </div>
          <div className="p-4 border rounded">
            <p className="text-gray-600">Products</p>
            <p className="text-2xl font-bold">{data.productsTotal}</p>
          </div>
          <div className="p-4 border rounded">
            <p className="text-gray-600">Orders</p>
            <p className="text-2xl font-bold">{data.ordersTotal}</p>
          </div>
        </div>
      )}
      {data && data.ordersByStatus && (
        <div className="mt-6">
          <h3 className="text-xl font-semibold mb-2">Orders by Status</h3>
          <ul className="list-disc ml-6">
            {data.ordersByStatus.map((s) => (
              <li key={s._id}>{s._id || "unknown"}: {s.count}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default Analytics;
